                  <defs>
                  <pattern id="pattern0_86_293" patternContentUnits="objectBoundingBox" width="1" height="1">
                  <use xlink:href="#image0_86_293" transform="matrix(0.000976562 0 0 0.000758086 0 -0.0321271)"/>
                  </pattern>
                  <image id="image0_86_293" width="1024" height="1536" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                  </defs>
                </svg>
            </div>
          </el-col>
          <el-col :span="10">
            <div class="grid-content overview-sidebar">
              <div class="scm-setup-heading" style="margin-bottom: 30px;">
                <h5>Hi There! 👋</h5>
                <h2 style="margin-top: 10px">
                  Welcome To Swift Certificate Manager
                </h2>
              </div>
              <div class="setup-form">
                <span style="font-size: 16px; font-weight: 500;">Select Your Preferences</span>
                <hr style="margin-top: 10px;"/>
                <el-form label-position="top" label-width="100px">
                  <el-form-item>
                    <div class="scm-setup-category-select">
                      <el-radio v-model="preference" label="instructor">Instructor</el-radio>
                      <el-radio v-model="preference" label="company">Company</el-radio>
                    </div>
                  </el-form-item>
                  <el-form-item :label="preferenceLabel('Name')" :error="errors.name">
                    <el-input
                        type="text"
                        v-model="info[preference + '_name']"
                        :placeholder="preference === 'instructor' ? 'Jon Deo' : 'C Company'">
                    </el-input>
                  </el-form-item>
                  <el-form-item :label="preferenceLabel('Signature')" :error="errors.signature">
                    <el-input
                        type="text"
                        v-model="info[preference + '_signature']"
                        placeholder="John Doe">
                    </el-input>
                  </el-form-item>
                  <el-form-item>
                    <span style="color: #7B7A7D; display: flex; justify-content: center;">Or</span>
                    <PhotoUploader
                        v-model="info[preference + '_signature_img']"
                    />
                  </el-form-item>

                  <el-form-item>
                    <el-checkbox 
                      v-model="info[preference + '_signature_img_enable']"
                      true-label="yes"
                      false-label="no"
                    >
                      Enable Image Signature
                    </el-checkbox>
                  </el-form-item>
                </el-form>
              </div>

              <div class="setup-next-box">
                <div class="setup-number">
                  <span class="setup-count">0{{active}}</span>
                  <span>/ 03</span>
                </div>
                <button class="el-button scm-primary-btn el-button--default" @click="nextHandler">Next</button>
              </div>
            </div>
          </el-col>
        </el-row>
      </div>
      <div class="scm_setup_step_2" v-if="active === 2">
        <Step2
            :active="active"
            @updateActive="updateStep"
        />
      </div>
      <div class="scm_setup_step_3" v-if="active === 3">
        <Step4
            :active="active"
            @updateActive="updateStep"
        />
      </div>
    </div>
  </div>
</template>

<script>
import PhotoUploader from "../../inputComponent/PhotoUploader";
import Step2 from "./Step2.vue";
import Step4 from "./Step4.vue";

export default {
  name: "step-1",
  components: {Step2, Step4, PhotoUploader},
  data() {
    return {
      fetching: false,
      saving: false,
      imageURL: window.SwiftCertificateManagerAdminVars.images_url,
      preference: 'instructor',
      info: {
        instructor_name: "",
        instructor_signature: "",
        instructor_signature_img: "",
        instructor_signature_img_enable: "no",
        company_name: "",
        company_signature: "",
        company_signature_img: "",
        company_signature_img_enable: "no",
      },
      errors: {
        name: "",
        signature: "",
      },
      active: parseInt(localStorage.getItem('scm_step_active')) || 1,
    };
  },
  created() {
    // Load saved data after component creation
    let storedData = localStorage.getItem('scm_onboarding_info');
    if (storedData) {
      const parsedData = JSON.parse(storedData);
      // Update info with saved data
      Object.keys(parsedData).forEach(key => {
        if (this.info.hasOwnProperty(key)) {
          this.info[key] = parsedData[key];
        }
      });

      // If preference is saved, restore it
      if (parsedData.preference) {
        this.preference = parsedData.preference;
      }
    }
  },
  methods: {
    preferenceLabel(val) {
      let label = `Type Your ${val}`;
      
      if (this.preference === 'company') {
        let name = this.preference.charAt(0).toUpperCase() + this.preference.slice(1);
        label = `Type Your ${name} ${val}`;
      }

      return label;
    },
    validateForm() {
      let valid = true;
      this.errors.name = this.info[this.preference + '_name']?.trim() === "" ? "This field is required" : "";
      this.errors.signature = this.info[this.preference + '_signature']?.trim() === "" &&
      !this.info[this.preference + '_signature_img'] ?
          "Either signature text or image is required" : "";

      if (this.errors.name || this.errors.signature) {
        valid = false;
      }
      return valid;
    },
    nextHandler() {
      if (!this.validateForm()) {
        return;
      }

      // Save preference along with other data
      const dataToSave = {
        ...this.info,
        preference: this.preference
      };
      localStorage.setItem('scm_onboarding_info', JSON.stringify(dataToSave));

      if (this.active < 3) {
        this.active += 1;
        localStorage.setItem('scm_step_active', this.active);
      }

      this.saveOnBoarding();
    },
    updateStep(value) {
      this.active = value;
      localStorage.setItem('scm_step_active', this.active);
    },

    saveOnBoarding() {
      this.saving = true;
      this.$post({
        action: "swift_certificate_manager_onboarding_info_ajax",
        route: "save_onboarding_info",
        info: {
          ...this.info,
          preference: this.preference
        },
        nonce: window.SwiftCertificateManagerAdminVars.nonce,
      })
          .then((response) => {
            this.$handleSuccess(response.data.message);
          })
          .fail((error) => {
            this.$handleError(error);
          })
          .always(() => {
            this.saving = false;
          });
    },
  },
  beforeMount() {
    if (this.appVars.is_onboarded === 'yes') {
      this.$router.push(
          {
            name: 'create_certificate',
            params: {}
          }
      )
    }
  },
};
</script>

