  .scm_onboarding {
    .scm-setup-bg {
      img {
        width: 100%;
      }
    }
    .setup-form {
      border: solid 1px #ddd;
      padding: 20px;
      border-radius: 10px;
    }
    .border-bottom {
      border-bottom: solid #ddd;
    }
    .scm-setup-category-select {
      label {
        border: solid #ddd;
        padding: 8px 15px;
        border-radius: 20px;
        margin-right: 5px;
        &.is-checked {
          border: solid #20104E;
          .el-radio__inner {
            border-color: #20104E;
            background: #20104E;
          }
          .el-radio__label {
            color: #20104E;
          }
        }

      }
    }
    .setup-next-box{
      display: flex;
      justify-content: space-between;
      margin-top: 30px;
      align-items: center;
    }

    .el-checkbox__input.is-checked + .el-checkbox__label {
        color: #20104E;
    }
   .is-checked .el-checkbox__inner {
        background-color: #20104E;
        border-color: #20104E;
    }
  }
</style>